   287→   * @return list of range class/datatype names
   288→   */
   289→  default java.util.List<String> getRangeNames(
   290→      com.grl.component.schema.PropertyNameResolver nameResolver) {
   291→    return switch (this) {
   292→      case SomeValuesFrom r -> r.filler()
   293→          .filter(f -> f instanceof org.semanticweb.owlapi.model.OWLClass)
   294→          .map(f -> nameResolver.resolve(f.asOWLClass()))
   295→          .stream().toList();
   296→      case AllValuesFrom r -> r.filler()
   297→          .filter(f -> f instanceof org.semanticweb.owlapi.model.OWLClass)
   298→          .map(f -> nameResolver.resolve(f.asOWLClass()))
   299→          .stream().toList();
   300→      case DataSomeValuesFrom r -> r.filler()
   301→          .filter(f -> f instanceof org.semanticweb.owlapi.model.OWLDatatype)
   302→          .map(f -> nameResolver.resolve(f.asOWLDatatype().getIRI()))
   303→          .stream().toList();
   304→      case DataAllValuesFrom r -> r.filler()
   305→          .filter(f -> f instanceof org.semanticweb.owlapi.model.OWLDatatype)
   306→          .map(f -> nameResolver.resolve(f.asOWLDatatype().getIRI()))
   307→          .stream().toList();
   308→      case OneOf oneOf -> oneOf.expression().individuals()
   309→          .flatMap(com.grl.component.owl.Narrow.to(
   310→              org.semanticweb.owlapi.model.OWLNamedIndividual.class))
   311→          .map(nameResolver::resolve)
   312→          .toList();
   313→      default -> java.util.List.of();
   314→    };
   315→  }
