    71→
    72→  /**
    73→   * If not in context cache already, create schema for given class and add to cache
    74→   *
    75→   * @param shortName shortname of class
    76→   */
    77→  public void addSchema(String shortName) {
    78→    schemaByRef.computeIfAbsent(shortName, s -> {
    79→      if (!computing.contains(s)) {
    80→        computing.add(s);
    81→        OWLClass cls = manager.getOWLDataFactory().getOWLClass(IRI.create(defaultOntologyPrefixIRI + shortName));
    82→        String description = OntologyUtil.getDescription(cls, ontology);
    83→        ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
    84→        computing.remove(s);
    85→        return resourceSchemaMapper.getSchema();
    86→      } else
    87→        return null; // already being computed, ignore to avoid infinite recursion
    88→    });
    89→  }
